public class PineconeFilterExpressionConverterTests {

    FilterExpressionConverter converter = new PineconeFilterExpressionConverter();

    @Test
    public void testEQ() {
        // country == "BG"
        String vectorExpr = this.converter.convertExpression(new Expression(EQ, new Key("country"), new Value("BG")));
        assertThat(vectorExpr).isEqualTo("{\"country\": {\"$eq\": \"BG\"}}");
    }

    @Test
    public void tesEqAndGte() {
        // genre == "drama" AND year >= 2020
        String vectorExpr = this.converter.convertExpression(new Expression(AND, new Expression(EQ, new Key("genre"), new Value("drama")), new Expression(GTE, new Key("year"), new Value(2020))));
        assertThat(vectorExpr).isEqualTo("{\"$and\": [{\"genre\": {\"$eq\": \"drama\"}},{\"year\": {\"$gte\": 2020}}]}");
    }

    @Test
    public void tesIn() {
        // genre in ["comedy", "documentary", "drama"]
        String vectorExpr = this.converter.convertExpression(new Expression(IN, new Key("genre"), new Value(List.of("comedy", "documentary", "drama"))));
        assertThat(vectorExpr).isEqualTo("{\"genre\": {\"$in\": [\"comedy\",\"documentary\",\"drama\"]}}");
    }

    @Test
    public void testNe() {
        // year >= 2020 OR country == "BG" AND city != "Sofia"
        String vectorExpr = this.converter.convertExpression(new Expression(OR, new Expression(GTE, new Key("year"), new Value(2020)), new Expression(AND, new Expression(EQ, new Key("country"), new Value("BG")), new Expression(NE, new Key("city"), new Value("Sofia")))));
        assertThat(vectorExpr).isEqualTo("{\"$or\": [{\"year\": {\"$gte\": 2020}},{\"$and\": [{\"country\": {\"$eq\": \"BG\"}},{\"city\": {\"$ne\": \"Sofia\"}}]}]}");
    }

    @Test
    public void testGroup() {
        // (year >= 2020 OR country == "BG") AND city NIN ["Sofia", "Plovdiv"]
        String vectorExpr = this.converter.convertExpression(new Expression(AND, new Group(new Expression(OR, new Expression(GTE, new Key("year"), new Value(2020)), new Expression(EQ, new Key("country"), new Value("BG")))), new Expression(NIN, new Key("city"), new Value(List.of("Sofia", "Plovdiv")))));
        assertThat(vectorExpr).isEqualTo("{\"$and\": [{\"$or\": [{\"year\": {\"$gte\": 2020}},{\"country\": {\"$eq\": \"BG\"}}]},{\"city\": {\"$nin\": [\"Sofia\",\"Plovdiv\"]}}]}");
