public class FilterExpressionTextParserTests {

    FilterExpressionTextParser parser = new FilterExpressionTextParser();

    @Test
    public void testEQ() {
        // country == "BG"
        Expression exp = this.parser.parse("country == 'BG'");
        assertThat(exp).isEqualTo(new Expression(EQ, new Key("country"), new Value("BG")));
        assertThat(this.parser.getCache().get("WHERE " + "country == 'BG'")).isEqualTo(exp);
    }

    @Test
    public void tesEqAndGte() {
        // genre == "drama" AND year >= 2020
        Expression exp = this.parser.parse("genre == 'drama' && year >= 2020");
        assertThat(exp).isEqualTo(new Expression(AND, new Expression(EQ, new Key("genre"), new Value("drama")), new Expression(GTE, new Key("year"), new Value(2020))));
        assertThat(this.parser.getCache().get("WHERE " + "genre == 'drama' && year >= 2020")).isEqualTo(exp);
    }

    @Test
    public void tesIn() {
        // genre in ["comedy", "documentary", "drama"]
        Expression exp = this.parser.parse("genre in ['comedy', 'documentary', 'drama']");
        assertThat(exp).isEqualTo(new Expression(IN, new Key("genre"), new Value(List.of("comedy", "documentary", "drama"))));
        assertThat(this.parser.getCache().get("WHERE " + "genre in ['comedy', 'documentary', 'drama']")).isEqualTo(exp);
    }

    @Test
    public void testNe() {
        // year >= 2020 OR country == "BG" AND city != "Sofia"
        Expression exp = this.parser.parse("year >= 2020 OR country == \"BG\" AND city != \"Sofia\"");
        assertThat(exp).isEqualTo(new Expression(OR, new Expression(GTE, new Key("year"), new Value(2020)), new Expression(AND, new Expression(EQ, new Key("country"), new Value("BG")), new Expression(NE, new Key("city"), new Value("Sofia")))));
        assertThat(this.parser.getCache().get("WHERE " + "year >= 2020 OR country == \"BG\" AND city != \"Sofia\"")).isEqualTo(exp);
    }

    @Test
    public void testGroup() {
        // (year >= 2020 OR country == "BG") AND city NIN ["Sofia", "Plovdiv"]
        Expression exp = this.parser.parse("(year >= 2020 OR country == \"BG\") AND city NIN [\"Sofia\", \"Plovdiv\"]");
        assertThat(exp).isEqualTo(new Expression(AND, new Group(new Expression(OR, new Expression(GTE, new Key("year"), new Value(2020)), new Expression(EQ, new Key("country"), new Value("BG")))), new Expression(NIN, new Key("city"), new Value(List.of("Sofia", "Plovdiv")))));
        assertThat(this.parser.getCache().get("WHERE " + "(year >= 2020 OR country == \"BG\") AND city NIN [\"Sofia\", \"Plovdiv\"]")).isEqualTo(exp);
    }

    @Test
    public void tesBoolean() {
        // isOpen == true AND year >= 2020 AND country IN ["BG", "NL", "US"]
        Expression exp = this.parser.parse("isOpen == true AND year >= 2020 AND country IN [\"BG\", \"NL\", \"US\"]");
        assertThat(exp).isEqualTo(new Expression(AND, new Expression(AND, new Expression(EQ, new Key("isOpen"), new Value(true)), new Expression(GTE, new Key("year"), new Value(2020))), new Expression(IN, new Key("country"), new Value(List.of("BG", "NL", "US")))));
        assertThat(this.parser.getCache().get("WHERE " + "isOpen == true AND year >= 2020 AND country IN [\"BG\", \"NL\", \"US\"]")).isEqualTo(exp);
    }

    @Test
    public void tesNot() {
        // NOT(isOpen == true AND year >= 2020 AND country IN ["BG", "NL", "US"])
        Expression exp = this.parser.parse("not(isOpen == true AND year >= 2020 AND country IN [\"BG\", \"NL\", \"US\"])");
        assertThat(exp).isEqualTo(new Expression(NOT, new Group(new Expression(AND, new Expression(AND, new Expression(EQ, new Key("isOpen"), new Value(true)), new Expression(GTE, new Key("year"), new Value(2020))), new Expression(IN, new Key("country"), new Value(List.of("BG", "NL", "US"))))), null));
        assertThat(this.parser.getCache().get("WHERE " + "not(isOpen == true AND year >= 2020 AND country IN [\"BG\", \"NL\", \"US\"])")).isEqualTo(exp);
    }

    @Test
    public void tesNotNin() {
        // NOT(country NOT IN ["BG", "NL", "US"])
        Expression exp = this.parser.parse("not(country NOT IN [\"BG\", \"NL\", \"US\"])");
        assertThat(exp).isEqualTo(new Expression(NOT, new Group(new Expression(NIN, new Key("country"), new Value(List.of("BG", "NL", "US")))), null));
    }

    @Test
    public void tesNotNin2() {
        // NOT country NOT IN ["BG", "NL", "US"]
        Expression exp = this.parser.parse("NOT country NOT IN [\"BG\", \"NL\", \"US\"]");
        assertThat(exp).isEqualTo(new Expression(NOT, new Expression(NIN, new Key("country"), new Value(List.of("BG", "NL", "US"))), null));
    }

    @Test
    public void tesNestedNot() {
        // NOT(isOpen == true AND year >= 2020 AND NOT(country IN ["BG", "NL", "US"]))
        Expression exp = this.parser.parse("not(isOpen == true AND year >= 2020 AND NOT(country IN [\"BG\", \"NL\", \"US\"]))");
        assertThat(exp).isEqualTo(new Expression(NOT, new Group(new Expression(AND, new Expression(AND, new Expression(EQ, new Key("isOpen"), new Value(true)), new Expression(GTE, new Key("year"), new Value(2020))), new Expression(NOT, new Group(new Expression(IN, new Key("country"), new Value(List.of("BG", "NL", "US")))), null))), null));
        assertThat(this.parser.getCache().get("WHERE " + "not(isOpen == true AND year >= 2020 AND NOT(country IN [\"BG\", \"NL\", \"US\"]))")).isEqualTo(exp);
    }

    @Test
    public void testDecimal() {
        // temperature >= -15.6 && temperature <= +20.13
        String expText = "temperature >= -15.6 && temperature <= +20.13";
        Expression exp = this.parser.parse(expText);
        assertThat(exp).isEqualTo(new Expression(AND, new Expression(GTE, new Key("temperature"), new Value(-15.6)), new Expression(LTE, new Key("temperature"), new Value(20.13))));
        assertThat(this.parser.getCache().get("WHERE " + expText)).isEqualTo(exp);
    }

    @Test
    public void testLong() {
        Expression exp2 = this.parser.parse("biz_id == 3L");
        Expression exp3 = this.parser.parse("biz_id == -5L");
        assertThat(exp2).isEqualTo(new Expression(EQ, new Key("biz_id"), new Value(3L)));
        assertThat(exp3).isEqualTo(new Expression(EQ, new Key("biz_id"), new Value(-5L)));
    }

    @Test
    public void testIdentifiers() {
        Expression exp = this.parser.parse("'country.1' == 'BG'");
        assertThat(exp).isEqualTo(new Expression(EQ, new Key("'country.1'"), new Value("BG")));
        exp = this.parser.parse("'country_1_2_3' == 'BG'");
        assertThat(exp).isEqualTo(new Expression(EQ, new Key("'country_1_2_3'"), new Value("BG")));
        exp = this.parser.parse("\"country 1 2 3\" == 'BG'");
        assertThat(exp).isEqualTo(new Expression(EQ, new Key("\"country 1 2 3\""), new Value("BG")));
    }

    @Test
    public void testUnescapedIdentifierWithUnderscores() {
        Expression exp = this.parser.parse("file_name == 'medicaid-wa-faqs.pdf'");
        assertThat(exp).isEqualTo(new Expression(EQ, new Key("file_name"), new Value("medicaid-wa-faqs.pdf")));
    }
